import{_ as a,o as e,c as n,a as i}from"./chunks/framework.BHSVNLI7.js";const b=JSON.parse('{"title":"QEMU 首次启动与 boot log 解读","description":"","frontmatter":{"title":"QEMU 首次启动与 boot log 解读","prerequisites":["busybox-rootfs"],"next":["gdb-debug-setup"],"difficulty":"beginner","tags":["qemu","boot","arm64","virt","bootlog"],"architectures":["arm64"],"kernel_version":"6.19"},"headers":[],"relativePath":"tutorials/foundations/qemu-first-boot.md","filePath":"tutorials/foundations/qemu-first-boot.md","lastUpdated":null}'),p={name:"tutorials/foundations/qemu-first-boot.md"};function l(t,s,r,o,c,d){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h2 id="做什么" tabindex="-1">做什么 <a class="header-anchor" href="#做什么" aria-label="Permalink to &quot;做什么&quot;">​</a></h2><p>这篇是整个环境搭建流程的高潮——我们终于要把编译好的内核和构建好的 rootfs 跑起来了。我们会用 QEMU 的 <code>virt</code> 机器型号启动 ARM64 内核，然后逐段解读启动日志里的每一行输出到底在说什么。理解 boot log 是内核学习的核心能力之一，因为后续调试驱动、排查问题时你面对的第一手信息就是这些日志。</p><h2 id="要了解什么" tabindex="-1">要了解什么 <a class="header-anchor" href="#要了解什么" aria-label="Permalink to &quot;要了解什么&quot;">​</a></h2><h3 id="qemu-virt-机器型号" tabindex="-1">QEMU virt 机器型号 <a class="header-anchor" href="#qemu-virt-机器型号" aria-label="Permalink to &quot;QEMU virt 机器型号&quot;">​</a></h3><p>QEMU 支持 ARM/ARM64 平台上的多种机器型号，从模拟真实开发板（比如 Raspberry Pi、Versatile Express）到纯虚拟机器。我们使用 <code>virt</code> 型号，这是 QEMU 推荐用于 ARM64 内核开发的虚拟平台。<code>virt</code> 不模拟任何真实的物理 SoC，而是提供一组干净的 VirtIO 设备——通用的虚拟化设备接口，性能好、代码干净、没有历史包袱。</p><p>用 <code>qemu-system-aarch64 -M help</code> 可以看到 QEMU 支持的所有 ARM64 机器型号，列表很长，从各种 BMC 开发板到 Xilinx Zynq 都有，但我们只关心 <code>virt</code>。</p><h3 id="启动命令" tabindex="-1">启动命令 <a class="header-anchor" href="#启动命令" aria-label="Permalink to &quot;启动命令&quot;">​</a></h3><p>项目提供了 <a href="./scripts/qemu-run.sh">qemu-run.sh</a> 脚本来简化 QEMU 的启动参数，它自动检测编译输出目录里的内核镜像和 rootfs 文件。运行方式很简单：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/qemu-run.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本在启动时会打印检测到的配置信息，让你确认它找到了正确的文件：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[INFO] === QEMU ARM System Emulation ===</span></span>
<span class="line"><span>[INFO] Architecture:     aarch64</span></span>
<span class="line"><span>[INFO] Machine:          virt</span></span>
<span class="line"><span>[INFO] CPU:              cortex-a72</span></span>
<span class="line"><span>[INFO] Memory:           1G</span></span>
<span class="line"><span>[INFO] SMP:              2</span></span>
<span class="line"><span>[INFO] Detected QEMU binary: qemu-system-aarch64</span></span>
<span class="line"><span>[INFO] Auto-detected kernel: .../out/build_latest_arm64/arch/arm64/boot/Image</span></span>
<span class="line"><span>[INFO] Auto-detected initrd: .../out/build_latest_arm64/rootfs.cpio.gz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>内核是 <code>Image</code>（上一篇编译出来的 ARM64 启动镜像），initrd 是 <code>rootfs.cpio.gz</code>（上上篇打包好的 BusyBox 根文件系统），DTB 不需要指定——QEMU virt 机器会自动生成设备树并传给内核。</p><p>启动后在 QEMU 的串口终端里按 <code>Ctrl+A, X</code> 可以退出。</p><h3 id="boot-log-逐段解读" tabindex="-1">Boot Log 逐段解读 <a class="header-anchor" href="#boot-log-逐段解读" aria-label="Permalink to &quot;Boot Log 逐段解读&quot;">​</a></h3><p>内核启动日志是一份时间线，每一行开头的时间戳 <code>[0.000000]</code> 表示从内核启动开始经过的秒数。我们来逐段拆解我们实际启动时的输出，理解内核启动的各个阶段。</p><p><strong>阶段一：内核解压与平台初始化（0.000000 - 0.010000）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Booting Linux on physical CPU 0x0000000000 [0x410fd083]</span></span>
<span class="line"><span>[    0.000000] Linux version 6.19.9 (charliechen@Charliechen) (aarch64-linux-gnu-gcc (GCC) 15.2.0, GNU ld (GNU Binutils) 2.46.0) #1 SMP PREEMPT Sat May  9 13:22:23 CST 2026</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>第一行告诉我们内核在 CPU 0 上启动，<code>0x410fd083</code> 是 CPU 的 MIDR（Main ID Register）值，QEMU 模拟的 cortex-a72 对应这个 ID。第二行是经典的内核版本字符串，包含了编译者、编译器版本、链接器版本、SMP/PREEMPT 标志和编译时间。这些信息看起来像是炫耀，但在排查问题时非常重要——你得确认跑的确实是你编译的那个内核，而不是系统自带的某个版本。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Machine model: linux,dummy-virt</span></span>
<span class="line"><span>[    0.000000] efi: UEFI not found.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>linux,dummy-virt</code> 是 QEMU virt 机器在设备树里的 <code>model</code> 属性值。UEFI not found 是正常的——我们没有配 UEFI 固件，内核直接从 boot loader 跳入启动，走的是传统的 device tree 启动路径。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Kernel command line: console=ttyAMA0,115200 root=/dev/ram0 rdinit=/init</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这是传给内核的启动参数。<code>console=ttyAMA0,115200</code> 指定串口控制台设备为 PL011 UART，波特率 115200；<code>root=/dev/ram0</code> 告诉内核根文件系统在内存盘（RAM disk）上；<code>rdinit=/init</code> 指定 initramfs 里内核首先执行的用户态程序。</p><p><strong>阶段二：内存与 CPU 初始化（0.000000 - 0.070000）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.000000] Zone ranges:</span></span>
<span class="line"><span>[    0.000000]   DMA      [mem 0x0000000040000000-0x000000007fffffff]</span></span>
<span class="line"><span>[    0.000000]   DMA32    empty</span></span>
<span class="line"><span>[    0.000000]   Normal   empty</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>内核把物理内存划分成不同的 zone。ARM64 的 1GB 内核全部落在 DMA zone（0x40000000-0x7FFFFFFF），因为我们的 QEMU 配了 1GB 内存，起始地址从 0x40000000 开始（virt 机器的 DRAM 基址）。DMA32 和 Normal zone 为空，因为 1GB 的地址范围不需要更高端的 zone。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.065793] Detected PIPT I-cache on CPU1</span></span>
<span class="line"><span>[    0.066669] CPU1: Booted secondary processor 0x0000000001 [0x410fd083]</span></span>
<span class="line"><span>[    0.070450] smp: Brought up 1 node, 2 CPUs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>SMP（Symmetric Multiprocessing）子系统把第二个 CPU 核启动起来了。CPU0 是主核（boot CPU），在内核启动的最早期就开始工作；CPU1 是从核（secondary CPU），稍后被 SMP 框架唤醒。两个核都识别为 cortex-a72。</p><p><strong>阶段三：内核子系统初始化（0.070000 - 0.500000）</strong></p><p>这一段日志最长，内核的各个子系统按固定顺序初始化——内存管理、调度器、定时器、中断控制器、时钟、设备模型、网络协议栈等等。每一个 &quot;Registered&quot; 或 &quot;initialized&quot; 都代表一个子系统完成了初始化。</p><p>几个值得关注的行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.221730] Serial: AMBA PL011 UART driver</span></span>
<span class="line"><span>[    0.270233] 9000000.pl011: ttyAMA0 at MMIO 0x9000000 (irq = 13, base_baud = 0) is a PL011 rev1</span></span>
<span class="line"><span>[    0.273819] printk: console [ttyAMA0] enabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>PL011 串口驱动初始化，注册了 <code>ttyAMA0</code> 设备。MMIO 地址 <code>0x9000000</code> 是 QEMU virt 机器为 PL011 UART 分配的物理地址。从这一刻开始，<code>printk</code> 的输出才会真正出现在我们的终端上——在此之前你看到的日志其实是内核先存在 log buffer 里，等串口驱动就绪后才一起刷出来的。</p><p><strong>阶段四：initramfs 解压与用户态启动（0.420000 - 0.990000）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.428951] Unpacking initramfs...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>内核开始解压我们的 cpio.gz initramfs。它会用 gzip 算法解压，然后按 cpio newc 格式解析文件列表，把每个文件创建到 rootfs 中。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[    0.987816] Freeing unused kernel memory: 3264K</span></span>
<span class="line"><span>[    0.989078] Run /init as init process</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>Freeing unused kernel memory</code> 是内核释放 <code>__init</code> 段的内存——这些代码只在启动阶段运行一次（比如各种 <code>__init</code> 函数），启动完成后就不再需要了，内核把这块内存回收给系统使用。然后内核执行 <code>/init</code>，控制权从内核态转到用户态。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=== PenguinLab Initramfs ===</span></span>
<span class="line"><span>Kernel: 6.19.9</span></span>
<span class="line"><span>Console: /dev/console</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Starting shell...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/bin/sh: can&#39;t access tty; job control turned off</span></span>
<span class="line"><span>~ #</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这是我们的 <code>/init</code> 脚本的输出。最后那个 <code>can&#39;t access tty; job control turned off</code> 不是致命错误——BusyBox 的 shell 在没有真正的 TTY 设备时会关闭 job control（Ctrl+Z、<code>fg</code>/<code>bg</code> 等），但基本的命令执行不受影响。</p><p>到这里，从 QEMU 加载内核镜像到进入 BusyBox shell，总共用了不到 1 秒。这个速度得益于我们精简的 mini config——没有多余的驱动初始化、没有等待硬件探测超时，整个启动链条干净利落。</p><h2 id="动手试试" tabindex="-1">动手试试 <a class="header-anchor" href="#动手试试" aria-label="Permalink to &quot;动手试试&quot;">​</a></h2><ol><li>运行 <code>./scripts/qemu-run.sh run</code>，等待进入 BusyBox shell</li><li>在 shell 里运行 <code>uname -a</code>，确认内核版本是 6.19.9，架构是 aarch64</li><li>运行 <code>cat /proc/cpuinfo</code>，看看 QEMU 报告的 CPU 信息</li><li>运行 <code>cat /proc/meminfo</code>，看看内核报告的内存使用情况</li><li>运行 <code>ls /sys/</code> 和 <code>ls /dev/</code>，确认 sysfs 和 devtmpfs 已正确挂载</li><li>按 <code>Ctrl+A, X</code> 退出 QEMU</li></ol><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>scripts/qemu-run.sh — 项目的 QEMU 启动脚本，<code>cmd_run()</code> 函数展示了完整的启动参数配置</li><li><a href="https://www.qemu.org/docs/master/system/target-arm.html" target="_blank" rel="noreferrer">QEMU ARM 系统模拟器文档</a> — QEMU 官方的 ARM/ARM64 仿真参考</li><li><a href="https://lwn.net/Articles/660404/" target="_blank" rel="noreferrer">Speeding up kernel development with QEMU</a> — LWN 经典文章，为什么 QEMU 是内核开发的最佳搭档</li></ul>`,44)])])}const m=a(p,[["render",l]]);export{b as __pageData,m as default};
